import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerDashboard = () => {
  const { user, logout } = useAuth();
  const { sensorData } = useSocket();
  const navigate = useNavigate();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [stats, setStats] = useState({
    totalSpent: 0,
    totalKg: 0,
    transactionCount: 0
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  const fetchTransactions = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions`);
      const data = response.data.data || response.data;
      setTransactions(data.slice(0, 3));
      
      const totalSpent = data.reduce((sum, t) => sum + (t.amountPaid || 0), 0);
      const totalKg = data.reduce((sum, t) => sum + (t.quantityKg || 0), 0);
      
      setStats({
        totalSpent,
        totalKg,
        transactionCount: data.length
      });
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      month: 'numeric',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      hour12: true
    }).toLowerCase();
  };

  const getInitials = () => {
    if (!user) return 'U';
    return `${user.firstName?.charAt(0) || ''}${user.lastName?.charAt(0) || ''}`;
  };

  return (
    <div className="dashboard-container">
      {/* Mobile Menu Toggle - Black Icon */}
      <button 
        className="mobile-menu-toggle"
        onClick={() => setSidebarOpen(!sidebarOpen)}
      >
        ☰
      </button>

      {/* Sidebar */}
      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
          <Link to="/customer/dashboard" className="logo" onClick={() => setSidebarOpen(false)}>
            {/* Changed to black logo icon */}
            <span className="logo-icon black-icon">⛭</span>
            <span className="logo-text black-text">AgriVend</span>
          </Link>
        </div>

        <nav className="sidebar-nav">
          <Link to="/customer/dashboard" className="nav-item active" onClick={() => setSidebarOpen(false)}>
            <span className="nav-icon black-icon">📊</span>
            <span>Dashboard</span>
          </Link>
          <Link to="/customer/transactions" className="nav-item" onClick={() => setSidebarOpen(false)}>
            <span className="nav-icon black-icon">📝</span>
            <span>Transactions</span>
          </Link>
          <Link to="/customer/returns" className="nav-item" onClick={() => setSidebarOpen(false)}>
            <span className="nav-icon black-icon">↩️</span>
            <span>Returns</span>
          </Link>
          <Link to="/customer/messages" className="nav-item" onClick={() => setSidebarOpen(false)}>
            <span className="nav-icon black-icon">💬</span>
            <span>Messages</span>
          </Link>
          <Link to="/customer/profile" className="nav-item" onClick={() => setSidebarOpen(false)}>
            <span className="nav-icon black-icon">👤</span>
            <span>Profile</span>
          </Link>
        </nav>

        <div className="sidebar-footer">
          <div className="user-info">
            <div className="user-avatar">{getInitials()}</div>
            <div className="user-details">
              <div className="user-name">{user?.firstName} {user?.lastName}</div>
              <div className="user-email">{user?.email}</div>
            </div>
          </div>
          <button onClick={handleLogout} className="logout-btn">
            <span className="black-icon">🚪</span>
            Logout
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {/* Welcome Section */}
        <div className="welcome-section">
          <h1 className="welcome-title">
            Welcome back, <span className="green-text">{user?.firstName || 'User'}</span>!
          </h1>
          <p className="welcome-subtitle">Here's what's happening with your account</p>
        </div>

        {/* Stats Cards */}
        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon-wrapper">
              <span className="stat-icon black-icon">📊</span>
            </div>
            <div className="stat-content">
              <div className="stat-label">Total Transactions</div>
              <div className="stat-value">{stats.transactionCount}</div>
            </div>
          </div>

          <div className="stat-card">
            <div className="stat-icon-wrapper">
              <span className="stat-icon black-icon">💰</span>
            </div>
            <div className="stat-content">
              <div className="stat-label">Total Spent</div>
              <div className="stat-value green-text">
                ₱{stats.totalSpent.toFixed(2)}
              </div>
            </div>
          </div>

          <div className="stat-card">
            <div className="stat-icon-wrapper">
              <span className="stat-icon black-icon">🌾</span>
            </div>
            <div className="stat-content">
              <div className="stat-label">Total Rice</div>
              <div className="stat-value">
                <span className="green-text">{stats.totalKg.toFixed(2)}</span> <span className="stat-unit">kg</span>
              </div>
            </div>
          </div>
        </div>

        {/* Machine Status - Optional */}
        {sensorData && (
          <div className="machine-status-card">
            <h2 className="section-title">Machine Status</h2>
            <div className="machine-status-grid">
              <div className="machine-status-item">
                <span className="status-label">Sinandomeng</span>
                <div className="status-value-wrapper">
                  <span className="status-value green-text">{sensorData.container1Level?.toFixed(1)} kg</span>
                  <span className={`status-badge ${sensorData.container1Stock?.toLowerCase()}`}>
                    {sensorData.container1Stock}
                  </span>
                </div>
              </div>
              <div className="machine-status-item">
                <span className="status-label">Dinorado</span>
                <div className="status-value-wrapper">
                  <span className="status-value green-text">{sensorData.container2Level?.toFixed(1)} kg</span>
                  <span className={`status-badge ${sensorData.container2Stock?.toLowerCase()}`}>
                    {sensorData.container2Stock}
                  </span>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Recent Transactions */}
        <div className="transactions-card">
          <div className="card-header">
            <h2 className="section-title">Recent Transactions</h2>
            <Link to="/customer/transactions" className="view-all-link">
              View All <span className="black-icon">→</span>
            </Link>
          </div>

          {loading ? (
            <div className="loading-spinner">Loading...</div>
          ) : transactions.length === 0 ? (
            <div className="empty-state">No transactions yet</div>
          ) : (
            <div className="transactions-list">
              {transactions.map((transaction) => (
                <div key={transaction._id} className="transaction-item">
                  <div className="transaction-info">
                    <div className="transaction-icon black-icon">🌾</div>
                    <div className="transaction-details">
                      <h3>{transaction.riceType} - {transaction.quantityKg}kg</h3>
                      <p>{formatDate(transaction.createdAt)}</p>
                    </div>
                  </div>
                  <div className="transaction-amount">
                    <div className="transaction-price green-text">₱{transaction.amountPaid}</div>
                    <Link 
                      to={`/customer/rate/${transaction.transactionId}`}
                      className="transaction-rate black-icon"
                    >
                      Rate this purchase
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Actions */}
        <div className="quick-actions">
          <Link to="/customer/returns/create" className="action-card">
            <div className="action-icon-wrapper">
              <span className="action-icon black-icon">↩️</span>
            </div>
            <h3 className="green-text">Request Return</h3>
            <p>Return a product if you're not satisfied</p>
          </Link>

          <Link to="/customer/messages" className="action-card">
            <div className="action-icon-wrapper">
              <span className="action-icon black-icon">💬</span>
            </div>
            <h3 className="green-text">Contact Support</h3>
            <p>Send us a message or ask for help</p>
          </Link>
        </div>
      </main>
    </div>
  );
};

export default CustomerDashboard;
